import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ServiceItem {
  id: string;
  name: string;
  description: string;
  price: number;
  type: 'base' | 'option' | 'multiplier';
  features?: string[];
  unit?: string;
  exclusiveGroup?: string; // For base services that replace each other
}

export interface CartItem {
  id: string;
  quantity: number;
  item: ServiceItem;
}

export interface Message {
  id: string;
  role: 'user' | 'model' | 'system';
  text: string;
  isTool?: boolean;
}

import React from 'react';
import { ServiceItem } from '../types';
import { Plus, Check } from 'lucide-react';

interface ServiceCardProps {
  service: ServiceItem;
  isSelected: boolean;
  onSelect: (service: ServiceItem) => void;
}

export const ServiceCard: React.FC<ServiceCardProps> = ({ service, isSelected, onSelect }) => {
  return (
    <div 
      className={`
        relative p-6 rounded-3xl border transition-all duration-300 cursor-pointer
        flex flex-col justify-between h-full group
        ${isSelected 
          ? 'bg-neutral-900/80 border-purple-500 shadow-[0_0_30px_rgba(168,85,247,0.15)]' 
          : 'bg-neutral-900/40 border-neutral-800 hover:border-neutral-700 hover:bg-neutral-900/60'
        }
      `}
      onClick={() => onSelect(service)}
    >
      <div>
        <div className="flex items-center gap-2 mb-4">
          <span className="text-xs font-medium px-2 py-1 rounded-full bg-neutral-800 text-neutral-400 border border-neutral-700">
            {service.id === 'short_mix' ? '믹싱 & 마스터링' : '믹싱 & 마스터링'}
          </span>
        </div>

        <h3 className="text-xl font-bold text-white mb-2">{service.name}</h3>
        <p className="text-neutral-400 text-sm mb-6 whitespace-pre-line leading-relaxed">
          {service.description}
        </p>

        {service.features && (
          <div className="space-y-2 mb-6">
            {service.features.map((feature, idx) => (
              <div key={idx} className="flex items-start gap-2 text-sm text-neutral-500">
                 <span className="text-neutral-600 mt-0.5">•</span>
                 <span>{feature}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="flex items-end justify-between mt-auto">
        <div className="flex items-baseline gap-1">
          <span className="text-2xl font-bold text-white">₩{service.price.toLocaleString()}</span>
          <span className="text-sm text-neutral-600">/ {service.unit}</span>
        </div>

        <button 
          className={`
            w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300
            ${isSelected 
              ? 'bg-purple-600 text-white rotate-0' 
              : 'bg-white text-black hover:bg-neutral-200 rotate-0'
            }
          `}
        >
          {isSelected ? <Check size={20} /> : <Plus size={20} />}
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { ServiceItem } from '../types';
import { Plus, Minus, Check } from 'lucide-react';

interface OptionCardProps {
  option: ServiceItem;
  quantity: number;
  onUpdate: (delta: number) => void;
  isMultiplier?: boolean;
  isActive?: boolean;
}

export const OptionCard: React.FC<OptionCardProps> = ({ 
  option, 
  quantity, 
  onUpdate, 
  isMultiplier = false,
  isActive = false
}) => {
  const isSelected = quantity > 0 || isActive;

  // Handle click for non-counter options (toggle behavior for logic, but UI shows plus)
  // For simplicity in this UI, we treat the main card click as +1, unless it's a multiplier toggle

  return (
    <div className={`
      relative p-5 rounded-2xl border transition-all duration-200
      flex flex-col justify-between min-h-[140px]
      ${isSelected || isActive
        ? (isMultiplier ? 'bg-indigo-900/20 border-indigo-500/50' : 'bg-neutral-800/50 border-neutral-700')
        : 'bg-neutral-900/40 border-neutral-800 hover:border-neutral-700 hover:bg-neutral-900/60'}
    `}>
      <div className="flex justify-between items-start mb-2">
        <div>
          <h4 className={`font-bold text-base ${isMultiplier ? 'text-indigo-400' : 'text-neutral-200'}`}>
            {option.name} 
            {option.features?.includes('INCLUDED') && (
              <span className="ml-2 text-[10px] bg-green-900/50 text-green-400 px-1.5 py-0.5 rounded border border-green-800">
                INCLUDED
              </span>
            )}
            {option.unit && !option.features?.includes('INCLUDED') && (
              <span className="ml-2 text-[10px] bg-neutral-800 text-neutral-500 px-1.5 py-0.5 rounded border border-neutral-700">
                {option.unit}
              </span>
            )}
          </h4>
          <p className="text-xs text-neutral-500 mt-1 leading-relaxed pr-8">
            {option.description}
          </p>
        </div>
      </div>

      <div className="flex items-end justify-between mt-auto pt-4">
         {isMultiplier ? (
             <div className="text-indigo-400 font-semibold text-sm">
                 x3.0 Surcharge <span className="text-[10px] block text-indigo-500/70">COMMERCIAL</span>
             </div>
         ) : (
            <div className="font-semibold text-white">
                {option.price === 0 ? (
                    <span className="text-green-500">FREE OPTION</span>
                ) : (
                    `₩${option.price.toLocaleString()}`
                )}
            </div>
         )}

         {/* Controls */}
         <div className="flex items-center gap-2">
            {isMultiplier ? (
                 <button 
                 onClick={() => onUpdate(isActive ? 0 : 1)} // Toggle
                 className={`
                    w-8 h-8 rounded-lg flex items-center justify-center transition-colors
                    ${isActive ? 'bg-indigo-600 text-white' : 'bg-neutral-800 text-neutral-400 hover:bg-neutral-700'}
                 `}
               >
                 {isActive ? <Check size={16} /> : <Plus size={16} />}
               </button>
            ) : (
                option.price === 0 ? (
                    <div className="w-8 h-8 rounded-lg bg-green-900/30 text-green-500 flex items-center justify-center border border-green-800/50">
                        <Check size={16} />
                    </div>
                ) : (
                    <>
                        {quantity > 0 && (
                            <>
                                <button 
                                    onClick={() => onUpdate(-1)}
                                    className="w-8 h-8 rounded-lg bg-neutral-800 text-neutral-400 hover:bg-neutral-700 flex items-center justify-center transition-colors"
                                >
                                    <Minus size={16} />
                                </button>
                                <span className="text-sm font-medium w-4 text-center">{quantity}</span>
                            </>
                        )}
                        <button 
                            onClick={() => onUpdate(1)}
                            className={`w-8 h-8 rounded-lg flex items-center justify-center transition-colors ${quantity > 0 ? 'bg-neutral-800 text-white hover:bg-neutral-700' : 'bg-neutral-800 text-neutral-400 hover:bg-neutral-700'}`}
                        >
                            <Plus size={16} />
                        </button>
                    </>
                )
            )}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Type, FunctionDeclaration, Schema } from "@google/genai";
import { Message } from '../types';
import { Sparkles, Send, Bot, User, Loader2 } from 'lucide-react';

// Define tools for the model
const tools: FunctionDeclaration[] = [
  {
    name: 'addToCart',
    description: 'Add a service or option to the user\'s cart.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        itemId: {
          type: Type.STRING,
          description: 'The ID of the item to add (e.g., short_mix, full_mix, pitch_correction, revision, add_person, add_track, add_minute, remove_signature, private_portfolio)',
        },
        quantity: {
          type: Type.NUMBER,
          description: 'Quantity to add (default 1). For base services, usually 1.',
        }
      },
      required: ['itemId']
    }
  },
  {
    name: 'setCommercial',
    description: 'Enable or disable commercial use multiplier.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        enabled: {
          type: Type.BOOLEAN,
          description: 'True to enable commercial mode (x3 price), false to disable.',
        }
      },
      required: ['enabled']
    }
  }
];

interface ChatProps {
  onToolCall: (toolName: string, args: any) => void;
}

export const Chat: React.FC<ChatProps> = ({ onToolCall }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: '안녕하세요! 작업하실 곡의 인원, MR포함 총 트랙 수, 보정 여부와 함께 상업적 이용 여부를 알려주시면 자동으로 견적을 도와드릴게요!'
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      if (!process.env.API_KEY) {
         throw new Error("API Key not found");
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Construct history for the API
      const history = messages.map(m => ({
          role: m.role === 'model' ? 'model' : 'user',
          parts: [{ text: m.text }]
      }));

      const model = 'gemini-2.5-flash-latest'; // Using flash for speed/cost in this tool

      const systemInstruction = `
        You are the "Smart Auto-Quote" assistant for "THE MILLI MIX", a mixing and mastering studio.
        Your goal is to help users select the right services.

        Prices:
        - Short Mix (<1min): 10,000 KRW (ID: short_mix)
        - Full Mix (<3min): 30,000 KRW (ID: full_mix)
        - Pitch Correction: 10,000 KRW/track (ID: pitch_correction)
        - Revision: 10,000 KRW (First free) (ID: revision)
        - Add Person: 10,000 KRW (ID: add_person)
        - Add Track: 10,000 KRW (ID: add_track)
        - Add Minute: 10,000 KRW (ID: add_minute)
        - Remove Signature: 50,000 KRW (ID: remove_signature)
        - Private Portfolio: 50,000 KRW (ID: private_portfolio)
        - Commercial Use: x3 Multiplier (ID: commercial)

        Rules:
        1. If the user describes their project (e.g., "I have a 3-minute song, 2 vocal tracks"), calculate and call the appropriate tools to build their quote.
        2. Always be polite and professional (Korean language).
        3. If you call a tool, briefly confirm what you did in the text response (e.g., "Short Mix와 보정 옵션을 추가했습니다.").
      `;

      const result = await ai.models.generateContent({
        model,
        contents: [...history, { role: 'user', parts: [{ text: userMsg.text }] }],
        config: {
          systemInstruction,
          tools: [{ functionDeclarations: tools }],
        }
      });

      const response = result.response;
      let responseText = '';

      // Handle Tool Calls
      const functionCalls = response.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {
            onToolCall(call.name, call.args);
        }
        // If there are tool calls, the model might not return text, or it might.
        // Usually we'd need a second turn to confirm, but for this simple UI we just show the model's text if present, 
        // or a generic "Applied" message if only tools were called and no text.
        responseText = response.text || "견적에 반영해드렸습니다.";
      } else {
        responseText = response.text || "죄송합니다. 다시 말씀해 주시겠어요?";
      }

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "오류가 발생했습니다. 잠시 후 다시 시도해주세요." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[500px] w-full bg-neutral-900/50 rounded-2xl border border-neutral-800 overflow-hidden relative">
        {/* Header */}
        <div className="p-4 border-b border-neutral-800 bg-neutral-900/80 backdrop-blur flex justify-between items-center">
            <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-purple-500 animate-pulse"></div>
                <span className="text-xs font-bold tracking-widest text-neutral-300">SMART AUTO-QUOTE</span>
            </div>
            <Sparkles size={14} className="text-purple-500" />
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-hide">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`
                        w-8 h-8 rounded-full flex items-center justify-center shrink-0
                        ${msg.role === 'model' ? 'bg-neutral-800 text-purple-400' : 'bg-neutral-200 text-neutral-900'}
                    `}>
                        {msg.role === 'model' ? <Bot size={16} /> : <User size={16} />}
                    </div>
                    <div className={`
                        max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed
                        ${msg.role === 'model' 
                            ? 'bg-neutral-800 text-neutral-200 rounded-tl-none' 
                            : 'bg-neutral-200 text-neutral-900 rounded-tr-none'}
                    `}>
                        {msg.text}
                    </div>
                </div>
            ))}
            {isLoading && (
                 <div className="flex gap-3">
                    <div className="w-8 h-8 rounded-full bg-neutral-800 text-purple-400 flex items-center justify-center shrink-0">
                        <Bot size={16} />
                    </div>
                    <div className="bg-neutral-800 rounded-2xl rounded-tl-none px-4 py-3 flex items-center">
                        <Loader2 size={16} className="animate-spin text-neutral-500" />
                    </div>
                 </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="p-4 bg-neutral-900 border-t border-neutral-800">
            <div className="relative">
                <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="작업 내용을 입력하세요..."
                    className="w-full bg-black/40 border border-neutral-700 rounded-xl py-3 pl-4 pr-12 text-sm text-white placeholder-neutral-600 focus:outline-none focus:border-purple-500 transition-colors"
                />
                <button 
                    onClick={handleSend}
                    disabled={isLoading}
                    className="absolute right-2 top-1/2 -translate-y-1/2 p-2 text-neutral-400 hover:text-white disabled:opacity-50 transition-colors"
                >
                    <Send size={16} />
                </button>
            </div>
            <div className="text-[10px] text-neutral-600 text-center mt-2">
                AUTO QUOTE ENGINE POWERED BY THE MILLI MIX
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Camera, ShoppingBag, X, ArrowRight, ExternalLink } from 'lucide-react';
import { ServiceCard } from './components/ServiceCard';
import { OptionCard } from './components/OptionCard';
import { Chat } from './components/Chat';
import { BASE_SERVICES, OPTIONS, COMMERCIAL_OPTION } from './constants';
import { CartItem, ServiceItem } from './types';

export default function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCommercial, setIsCommercial] = useState(false);

  // Calculate total
  const subtotal = cart.reduce((sum, item) => sum + (item.item.price * item.quantity), 0);
  const total = isCommercial ? subtotal * 3 : subtotal;

  // Handlers
  const handleServiceSelect = (service: ServiceItem) => {
    setCart(prev => {
      // Remove other base services
      const filtered = prev.filter(item => item.item.type !== 'base');
      // Add new service
      return [...filtered, { id: service.id, quantity: 1, item: service }];
    });
  };

  const handleOptionUpdate = (optionId: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === optionId);
      const option = OPTIONS.find(o => o.id === optionId);
      if (!option) return prev;

      if (existing) {
        const newQty = existing.quantity + delta;
        if (newQty <= 0) {
          return prev.filter(i => i.id !== optionId);
        }
        return prev.map(i => i.id === optionId ? { ...i, quantity: newQty } : i);
      } else if (delta > 0) {
        return [...prev, { id: optionId, quantity: delta, item: option }];
      }
      return prev;
    });
  };

  const handleCommercialToggle = () => {
    setIsCommercial(!isCommercial);
  };

  // Tool Call Handler (from AI)
  const handleToolCall = (name: string, args: any) => {
    if (name === 'addToCart') {
      const { itemId, quantity = 1 } = args;

      // Check if it's a base service
      const baseService = BASE_SERVICES.find(s => s.id === itemId);
      if (baseService) {
        handleServiceSelect(baseService);
        return;
      }

      // Check options
      const option = OPTIONS.find(o => o.id === itemId);
      if (option) {
         // If it already exists, update quantity, otherwise add
         setCart(prev => {
             const existing = prev.find(i => i.id === itemId);
             if (existing) {
                 return prev.map(i => i.id === itemId ? { ...i, quantity: existing.quantity + quantity } : i);
             }
             return [...prev, { id: itemId, quantity, item: option }];
         });
      }
    } else if (name === 'setCommercial') {
      setIsCommercial(args.enabled);
    }
  };

  const handleSaveScreen = () => {
    window.print();
  };

  return (
    <div className="min-h-screen bg-[#050505] text-neutral-200 selection:bg-purple-500/30 font-inter pb-20">

      {/* Header */}
      <header className="sticky top-0 z-50 bg-[#050505]/80 backdrop-blur-md border-b border-neutral-900">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
            <div className="flex-1 hidden md:flex gap-8 text-sm font-medium text-neutral-400">
                <a href="#" className="text-white hover:text-purple-400 transition-colors">Services</a>
                <a href="#" className="hover:text-purple-400 transition-colors">Portfolio</a>
            </div>

            <div className="flex-1 text-center">
                <h1 className="text-2xl font-bold tracking-[0.2em] text-white">THE MILLI MIX</h1>
                <p className="text-[10px] text-neutral-500 tracking-widest mt-1">믹싱 마스터링 커미션</p>
            </div>

            <div className="flex-1 flex justify-end">
                <button onClick={handleSaveScreen} className="flex items-center gap-2 text-xs font-medium text-neutral-400 hover:text-white transition-colors border border-neutral-800 hover:border-neutral-600 rounded-full px-4 py-2">
                    <Camera size={14} />
                    <span>Save Screen</span>
                </button>
            </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 py-12 grid grid-cols-1 lg:grid-cols-12 gap-12">

        {/* Left Column: Services & Options */}
        <div className="lg:col-span-8 space-y-12">

            {/* Section 1: Main Services */}
            <section>
                <div className="mb-6">
                    <h2 className="text-xl font-bold text-white mb-1">서비스 선택</h2>
                    <p className="text-sm text-neutral-500">곡의 퀄리티를 완성할 핵심 엔지니어링 서비스입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-6">
                    {BASE_SERVICES.map(service => (
                        <ServiceCard 
                            key={service.id}
                            service={service}
                            isSelected={cart.some(item => item.id === service.id)}
                            onSelect={handleServiceSelect}
                        />
                    ))}
                </div>
            </section>

            {/* Section 2: Options */}
            <section>
                <div className="mb-6">
                    <h2 className="text-xl font-bold text-white mb-1">에디팅 & 옵션</h2>
                    <p className="text-sm text-neutral-500">필요에 따라 추가적인 디테일을 보강할 수 있는 옵션 항목입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-4">
                    {OPTIONS.map(option => (
                        <OptionCard
                            key={option.id}
                            option={option}
                            quantity={cart.find(i => i.id === option.id)?.quantity || 0}
                            onUpdate={(delta) => handleOptionUpdate(option.id, delta)}
                        />
                    ))}
                    {/* Commercial Option */}
                    <OptionCard 
                        option={COMMERCIAL_OPTION}
                        quantity={0}
                        onUpdate={handleCommercialToggle}
                        isMultiplier={true}
                        isActive={isCommercial}
                    />
                </div>
            </section>

            {/* Custom Project Banner */}
            <section>
                 <div className="relative overflow-hidden rounded-2xl border border-neutral-800 bg-neutral-900/30 p-8 flex items-center justify-between">
                    <div className="absolute top-0 right-0 p-32 bg-purple-900/10 blur-[100px] rounded-full pointer-events-none"></div>
                    <div>
                        <h3 className="text-xl font-bold text-white mb-2">Custom Project</h3>
                        <p className="text-sm text-neutral-500">앨범 단위(EP/LP) 또는 정기 작업 문의는 별도의 커스텀 견적이 적용됩니다.</p>
                    </div>
                    <button className="flex items-center gap-2 text-sm font-medium text-neutral-300 hover:text-white border border-neutral-700 hover:border-neutral-500 rounded-lg px-5 py-2.5 transition-all z-10">
                        상담하기
                        <ArrowRight size={14} />
                    </button>
                 </div>
            </section>
        </div>

        {/* Right Column: Sidebar (Sticky) */}
        <div className="lg:col-span-4 space-y-6">

            {/* Cart Summary */}
            <div className="bg-neutral-900/50 border border-neutral-800 rounded-2xl p-6 min-h-[300px] flex flex-col">
                <div className="flex items-center justify-between mb-6 pb-4 border-b border-neutral-800">
                    <h3 className="font-bold text-neutral-200 flex items-center gap-2">
                        <ShoppingBag size={18} />
                        Your Estimate
                    </h3>
                    {cart.length > 0 && (
                        <button 
                            onClick={() => { setCart([]); setIsCommercial(false); }}
                            className="text-xs text-neutral-500 hover:text-red-400 transition-colors"
                        >
                            Reset
                        </button>
                    )}
                </div>

                {cart.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-neutral-600 gap-4">
                        <div className="w-16 h-16 rounded-full bg-neutral-800/50 flex items-center justify-center">
                            <ShoppingBag size={24} className="opacity-50" />
                        </div>
                        <span className="text-sm font-medium tracking-wide">YOUR CART IS EMPTY</span>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col">
                        <div className="flex-1 space-y-4 mb-6">
                            {cart.map(cartItem => (
                                <div key={cartItem.id} className="flex justify-between items-start text-sm group">
                                    <div className="pr-4">
                                        <div className="text-neutral-200 font-medium">{cartItem.item.name}</div>
                                        {cartItem.quantity > 1 && (
