import React, { useState, useEffect } from 'react';
import { Camera, ShoppingBag, X, ArrowRight, Sparkles } from 'lucide-react';
import { ServiceCard } from './components/ServiceCard';
import { OptionCard } from './components/OptionCard';
import { Chat } from './components/Chat';
import { BASE_SERVICES, OPTIONS, COMMERCIAL_OPTION } from './constants';
import { CartItem, ServiceItem } from './types';

export default function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCommercial, setIsCommercial] = useState(false);

  // Calculate total
  const subtotal = cart.reduce((sum, item) => sum + (item.item.price * item.quantity), 0);
  const total = isCommercial ? subtotal * 3 : subtotal;

  // Handlers
  const handleServiceSelect = (service: ServiceItem) => {
    setCart(prev => {
      // Remove other base services
      const filtered = prev.filter(item => item.item.type !== 'base');
      // Add new service
      return [...filtered, { id: service.id, quantity: 1, item: service }];
    });
  };

  const handleOptionUpdate = (optionId: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === optionId);
      const option = OPTIONS.find(o => o.id === optionId);
      if (!option) return prev;

      if (existing) {
        const newQty = existing.quantity + delta;
        if (newQty <= 0) {
          return prev.filter(i => i.id !== optionId);
        }
        return prev.map(i => i.id === optionId ? { ...i, quantity: newQty } : i);
      } else if (delta > 0) {
        return [...prev, { id: optionId, quantity: delta, item: option }];
      }
      return prev;
    });
  };

  const handleCommercialToggle = () => {
    setIsCommercial(!isCommercial);
  };

  // Tool Call Handler (from AI)
  const handleToolCall = (name: string, args: any) => {
    if (name === 'addToCart') {
      const { itemId, quantity = 1 } = args;

      // Check if it's a base service
      const baseService = BASE_SERVICES.find(s => s.id === itemId);
      if (baseService) {
        handleServiceSelect(baseService);
        return;
      }

      // Check options
      const option = OPTIONS.find(o => o.id === itemId);
      if (option) {
         setCart(prev => {
             const existing = prev.find(i => i.id === itemId);
             if (existing) {
                 return prev.map(i => i.id === itemId ? { ...i, quantity: existing.quantity + quantity } : i);
             }
             return [...prev, { id: itemId, quantity, item: option }];
         });
      }
    } else if (name === 'setCommercial') {
      setIsCommercial(args.enabled);
    }
  };

  const handleSaveScreen = () => {
    window.print();
  };

  return (
    <div className="min-h-screen bg-[#050505] text-neutral-200 selection:bg-purple-500/30 font-inter pb-32">

      {/* Hero Header */}
      <header className="pt-32 pb-16 text-center">
        <div className="animate-fade-in-down">
            <h1 className="text-4xl md:text-5xl font-light tracking-[0.3em] text-white mb-4">THE MILLI MIX</h1>
            <p className="text-[10px] text-neutral-500 tracking-[0.4em] uppercase">믹싱 마스터링 커미션</p>
        </div>

        <nav className="flex items-center justify-center gap-12 mt-20 text-[11px] font-medium tracking-widest text-neutral-500 uppercase">
            <a href="#" className="hover:text-white transition-colors border-b border-white pb-1 text-white">Services</a>
            <a href="#" className="hover:text-white transition-colors border-b border-transparent pb-1">Portfolio</a>
            <button onClick={handleSaveScreen} className="flex items-center gap-2 hover:text-white transition-colors border-b border-transparent pb-1">
                <Camera size={14} />
                <span>Save Screen</span>
            </button>
        </nav>
      </header>

      <main className="max-w-7xl mx-auto px-6 grid grid-cols-1 lg:grid-cols-12 gap-x-12 gap-y-16">

        {/* Left Column: Services & Options */}
        <div className="lg:col-span-8 space-y-16">

            {/* Section 1: Main Services */}
            <section>
                <div className="mb-8">
                    <h2 className="text-xl font-normal text-white mb-2">서비스 선택</h2>
                    <p className="text-xs text-neutral-500 font-light">곡의 퀄리티를 완성할 핵심 엔지니어링 서비스입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-6">
                    {BASE_SERVICES.map(service => (
                        <ServiceCard 
                            key={service.id}
                            service={service}
                            isSelected={cart.some(item => item.id === service.id)}
                            onSelect={handleServiceSelect}
                        />
                    ))}
                </div>
            </section>

            {/* Section 2: Options */}
            <section>
                <div className="mb-8">
                    <h2 className="text-xl font-normal text-white mb-2">에디팅 & 옵션</h2>
                    <p className="text-xs text-neutral-500 font-light">필요에 따라 추가적인 디테일을 보강할 수 있는 옵션 항목입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-4">
                    {OPTIONS.map(option => (
                        <OptionCard
                            key={option.id}
                            option={option}
                            quantity={cart.find(i => i.id === option.id)?.quantity || 0}
                            onUpdate={(delta) => handleOptionUpdate(option.id, delta)}
                        />
                    ))}
                    {/* Commercial Option - Spans Full Width */}
                    <div className="md:col-span-2 mt-2">
                        <OptionCard 
                            option={COMMERCIAL_OPTION}
                            quantity={0}
                            onUpdate={handleCommercialToggle}
                            isMultiplier={true}
                            isActive={isCommercial}
                        />
                    </div>
                </div>
            </section>

            {/* Custom Project Banner */}
            <section>
                 <div className="relative overflow-hidden rounded-2xl border border-dashed border-neutral-800 bg-[#080808] p-8 flex items-center justify-between">
                    <div>
                        <h3 className="text-xl font-bold text-white mb-2">Custom Project</h3>
                        <p className="text-sm text-neutral-500">앨범 단위(EP/LP) 또는 정기 작업 문의는 별도의 커스텀 견적이 적용됩니다.</p>
                    </div>
                    <button className="flex items-center gap-2 text-xs font-medium text-neutral-300 hover:text-white border border-neutral-800 hover:border-neutral-600 rounded px-5 py-3 transition-all z-10 bg-neutral-900/50">
                        상담하기
                        <ArrowRight size={14} />
                    </button>
                 </div>
            </section>
        </div>

        {/* Right Column: Sidebar (Sticky) */}
        <div className="lg:col-span-4 space-y-6">

            {/* Cart Summary */}
            <div className="bg-[#080808] border border-neutral-900 rounded-2xl min-h-[300px] flex flex-col relative overflow-hidden">
                {cart.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-neutral-600 gap-5 py-20">
                        <div className="w-16 h-16 rounded-full border-2 border-neutral-800/50 flex items-center justify-center text-neutral-700">
                            <ShoppingBag size={20} />
                        </div>
                        <span className="text-[10px] font-semibold tracking-[0.2em] text-neutral-600">YOUR CART IS EMPTY</span>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col p-6">
                        <div className="flex items-center justify-between mb-8 pb-4 border-b border-neutral-900">
                             <div className="flex items-center gap-2 text-neutral-400">
                                <ShoppingBag size={14} />
                                <span className="text-xs font-medium tracking-widest uppercase">Estimate</span>
                             </div>
                             <button 
                                onClick={() => { setCart([]); setIsCommercial(false); }}
                                className="text-[10px] text-neutral-600 hover:text-red-400 transition-colors uppercase tracking-wider"
                            >
                                Clear All
                            </button>
                        </div>

                        <div className="flex-1 space-y-4 mb-8">
                            {cart.map(cartItem => (
                                <div key={cartItem.id} className="flex justify-between items-start text-sm group">
                                    <div className="pr-4">
                                        <div className="text-neutral-300 font-medium mb-1">{cartItem.item.name}</div>
                                        {cartItem.quantity > 1 && (
                                            <div className="inline-flex items-center text-[10px] bg-neutral-900 text-neutral-500 px-1.5 py-0.5 rounded">Qty: {cartItem.quantity}</div>
                                        )}
                                    </div>
                                    <div className="text-white font-medium whitespace-nowrap">
                                        ₩{(cartItem.item.price * cartItem.quantity).toLocaleString()}
                                    </div>
                                </div>
                            ))}
                            {isCommercial && (
                                <div className="flex justify-between items-center text-sm pt-4 border-t border-neutral-900 text-indigo-400">
                                    <div className="font-medium flex items-center gap-2">
                                        Commercial Use
                                        <span className="text-[10px] bg-indigo-950 text-indigo-300 px-1.5 py-0.5 rounded border border-indigo-900/50">x3.0</span>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="pt-6 border-t border-neutral-900 mt-auto">
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-neutral-500 text-xs uppercase tracking-wider">Total</span>
                                <span className="text-2xl font-bold text-white tracking-tight">₩{total.toLocaleString()}</span>
                            </div>
                            <p className="text-[10px] text-neutral-700 text-right">VAT included</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Smart Chat */}
            <Chat onToolCall={handleToolCall} />

            <div className="text-center">
                 <p className="text-[9px] text-neutral-700 tracking-[0.2em] mt-8 uppercase">Auto Quote Engine Powered by The Milli Mix</p>
            </div>

        </div>

      </main>

      {/* Footer */}
      <footer className="text-center py-24 text-[10px] text-neutral-600 tracking-[0.3em] font-light">
        THE MILLI MIX <br/><br/> © 2026 THE MILLI MIX. PROFESSIONAL AUDIO ENGINEERING.
      </footer>
    </div>
  );
}

