};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { Message } from '../types';
import { Sparkles, Send, Bot, User, Loader2 } from 'lucide-react';

const tools: FunctionDeclaration[] = [
  {
    name: 'addToCart',
    description: 'Add a service or option to the user\'s cart.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        itemId: {
          type: Type.STRING,
          description: 'The ID of the item to add (e.g., short_mix, full_mix, pitch_correction, revision, add_person, add_track, add_minute, remove_signature, private_portfolio)',
        },
        quantity: {
          type: Type.NUMBER,
          description: 'Quantity to add (default 1). For base services, usually 1.',
        }
      },
      required: ['itemId']
    }
  },
  {
    name: 'setCommercial',
    description: 'Enable or disable commercial use multiplier.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        enabled: {
          type: Type.BOOLEAN,
          description: 'True to enable commercial mode (x3 price), false to disable.',
        }
      },
      required: ['enabled']
    }
  }
];

interface ChatProps {
  onToolCall: (toolName: string, args: any) => void;
}

export const Chat: React.FC<ChatProps> = ({ onToolCall }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: '안녕하세요! 작업하실 곡의 인원, MR포함 총 트랙 수, 보정 여부와 함께 상업적 이용 여부를 알려주시면 자동으로 견적을 도와드릴게요!'
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      if (!process.env.API_KEY) {
         throw new Error("API Key not found");
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const history = messages.map(m => ({
          role: m.role === 'model' ? 'model' : 'user',
          parts: [{ text: m.text }]
      }));

      const model = 'gemini-2.5-flash-latest';

      const systemInstruction = `
        You are the "Smart Auto-Quote" assistant for "THE MILLI MIX".
        Prices:
        - Short Mix: 10,000 KRW (short_mix)
        - Full Mix: 30,000 KRW (full_mix)
        - Options (10k each): pitch_correction, revision, add_person, add_track, add_minute
        - Remove Signature/Private: 50,000 KRW
        - Commercial: x3
        If user describes a project, use tools to add items. Confirm actions briefly in Korean.
      `;

      const result = await ai.models.generateContent({
        model,
        contents: [...history, { role: 'user', parts: [{ text: userMsg.text }] }],
        config: {
          systemInstruction,
          tools: [{ functionDeclarations: tools }],
        }
      });

      const response = result.response;
      let responseText = '';

      const functionCalls = response.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {
            onToolCall(call.name, call.args);
        }
        responseText = response.text || "견적에 반영해드렸습니다.";
      } else {
        responseText = response.text || "죄송합니다. 다시 말씀해 주시겠어요?";
      }

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "오류가 발생했습니다." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[400px] w-full bg-[#080808] rounded-2xl border border-neutral-900 overflow-hidden relative">
        {/* Header */}
        <div className="p-4 border-b border-neutral-900 flex justify-between items-center bg-[#0a0a0a]">
            <div className="flex items-center gap-2">
                <div className="w-1.5 h-1.5 rounded-full bg-purple-500"></div>
                <span className="text-[10px] font-bold tracking-[0.2em] text-neutral-400 uppercase">SMART AUTO-QUOTE</span>
            </div>
            <Sparkles size={12} className="text-purple-500" />
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-5 space-y-6 scrollbar-hide">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`
                        w-6 h-6 rounded-full flex items-center justify-center shrink-0 border
                        ${msg.role === 'model' ? 'bg-[#111] border-neutral-800 text-purple-400' : 'bg-neutral-800 border-neutral-700 text-neutral-300'}
                    `}>
                        {msg.role === 'model' ? <Bot size={12} /> : <User size={12} />}
                    </div>
                    <div className={`
                        max-w-[85%] rounded-lg px-3 py-2 text-xs leading-relaxed
                        ${msg.role === 'model' 
                            ? 'bg-[#161616] text-neutral-300 rounded-tl-none border border-neutral-800' 
                            : 'bg-neutral-800 text-neutral-200 rounded-tr-none border border-neutral-700'}
                    `}>
                        {msg.text}
                    </div>
                </div>
            ))}
            {isLoading && (
                 <div className="flex gap-3">
                    <div className="w-6 h-6 rounded-full bg-[#111] border border-neutral-800 text-purple-400 flex items-center justify-center shrink-0">
                        <Bot size={12} />
                    </div>
                    <div className="bg-[#161616] border border-neutral-800 rounded-lg rounded-tl-none px-3 py-2 flex items-center">
                        <Loader2 size={12} className="animate-spin text-neutral-500" />
                    </div>
                 </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="p-3 bg-[#0a0a0a] border-t border-neutral-900">
            <div className="relative">
                <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="작업 내용을 입력하세요..."
                    className="w-full bg-[#050505] border border-neutral-800 rounded-lg py-2.5 pl-3 pr-10 text-xs text-white placeholder-neutral-700 focus:outline-none focus:border-neutral-600 transition-colors"
                />
                <button 
                    onClick={handleSend}
                    disabled={isLoading}
                    className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-neutral-600 hover:text-white disabled:opacity-50 transition-colors"
                >
                    <Send size={12} />
                </button>
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
