      // Check options
      const option = OPTIONS.find(o => o.id === itemId);
      if (option) {
         setCart(prev => {
             const existing = prev.find(i => i.id === itemId);
             if (existing) {
                 return prev.map(i => i.id === itemId ? { ...i, quantity: existing.quantity + quantity } : i);
             }
             return [...prev, { id: itemId, quantity, item: option }];
         });
      }
    } else if (name === 'setCommercial') {
      setIsCommercial(args.enabled);
    }
  };

