import React from 'react';
import { ServiceItem } from '../types';
import { Plus, Minus, Check, Sparkles } from 'lucide-react';

interface OptionCardProps {
  option: ServiceItem;
  quantity: number;
  onUpdate: (delta: number) => void;
  isMultiplier?: boolean;
  isActive?: boolean;
}

export const OptionCard: React.FC<OptionCardProps> = ({ 
  option, 
  quantity, 
  onUpdate, 
  isMultiplier = false,
  isActive = false
}) => {
  const isSelected = quantity > 0 || isActive;

  return (
    <div className={`
      relative px-5 py-4 rounded-xl border transition-all duration-200
      flex justify-between items-center group min-h-[80px]
      ${isMultiplier 
        ? (isActive ? 'bg-[#0F0B1A] border-indigo-900/50' : 'bg-[#0B0810] border-[#1A1625] hover:border-indigo-900/30') 
        : (isSelected ? 'bg-[#0F0F0F] border-neutral-700' : 'bg-[#0a0a0a] border-[#1a1a1a] hover:border-neutral-800')
      }
    `}>
      {/* Left Content */}
      <div className="flex-1 pr-4">
        <div className="flex items-center gap-2 mb-1">
          <h4 className={`font-bold text-sm ${isMultiplier ? 'text-indigo-200' : 'text-neutral-200'}`}>
            {option.name} 
          </h4>
          {option.unit && !option.features?.includes('INCLUDED') && !isMultiplier && (
              <span className="text-[9px] bg-[#161616] text-neutral-500 px-1.5 py-0.5 rounded border border-[#222]">
                {option.unit}
              </span>
            )}
           {isMultiplier && (
               <span className="text-[9px] bg-indigo-500/10 text-indigo-400 px-1.5 py-0.5 rounded border border-indigo-500/20">
                $
              </span>
           )}
        </div>
        <p className={`text-[10px] ${isMultiplier ? 'text-indigo-400/60' : 'text-neutral-500'} leading-relaxed`}>
            {option.description}
        </p>
      </div>

      {/* Right Content */}
      <div className="flex items-center gap-4 shrink-0">
         {isMultiplier ? (
             <div className="text-right">
                 <span className="block text-indigo-400 font-bold text-xs">x3.0</span>
                 <span className="block text-[9px] text-indigo-600 font-medium tracking-wider text-right uppercase">COMMERCIAL</span>
             </div>
         ) : (
            <div className="font-bold text-white text-xs">
                {option.features?.includes('INCLUDED') ? (
                    <span className="text-green-500 font-bold text-[9px] tracking-wide">INCLUDED</span>
                ) : (
                    `₩${option.price.toLocaleString()}`
                )}
            </div>
         )}

         {/* Button */}
         {isMultiplier ? (
             <button 
                onClick={() => onUpdate(isActive ? 0 : 1)}
                className={`
                   w-7 h-7 rounded-lg flex items-center justify-center transition-colors
                   ${isActive ? 'bg-indigo-600 text-white' : 'bg-[#1A1625] text-indigo-900 hover:bg-[#251f36]'}
                `}
              >
                {isActive ? <Check size={14} /> : <Plus size={14} />}
              </button>
         ) : option.features?.includes('INCLUDED') ? (
             <div className="w-7 h-7 rounded-lg bg-green-900/20 text-green-500 flex items-center justify-center border border-green-900/30">
                 <Check size={12} />
             </div>
         ) : (
            <div className="flex items-center bg-[#161616] rounded-lg border border-[#222]">
                {quantity > 0 && (
                    <>
                        <button 
                            onClick={() => onUpdate(-1)}
                            className="w-7 h-7 flex items-center justify-center text-neutral-400 hover:text-white transition-colors"
                        >
                            <Minus size={12} />
                        </button>
                        <span className="text-[10px] font-medium w-4 text-center text-white">{quantity}</span>
                    </>
                )}
                <button 
                    onClick={() => onUpdate(1)}
                    className={`w-7 h-7 flex items-center justify-center transition-colors ${quantity > 0 ? 'text-white hover:bg-neutral-800 rounded-r-lg' : 'text-neutral-400 hover:text-white hover:bg-neutral-800 rounded-lg'}`}
                >
                    <Plus size={12} />
                </button>
            </div>
         )}
      </div>
    </div>
  );
};

