                 <span className="block text-[10px] text-indigo-600 font-medium tracking-wider text-right uppercase">COMMERCIAL</span>
             </div>
         ) : (
            <div className="font-bold text-white text-sm">
                {option.features?.includes('INCLUDED') ? (
                    <span className="text-green-500 font-bold text-[10px] tracking-wide">INCLUDED</span>
                ) : (
                    `₩${option.price.toLocaleString()}`
                )}
            </div>
         )}

         {/* Button */}
         {isMultiplier ? (
             <button 
                onClick={() => onUpdate(isActive ? 0 : 1)}
                className={`
                   w-8 h-8 rounded-lg flex items-center justify-center transition-colors
                   ${isActive ? 'bg-indigo-600 text-white' : 'bg-[#1A1625] text-indigo-900 hover:bg-[#251f36]'}
                `}
              >
                {isActive ? <Check size={16} /> : <Plus size={16} />}
              </button>
         ) : option.features?.includes('INCLUDED') ? (
             <div className="w-8 h-8 rounded-lg bg-green-900/20 text-green-500 flex items-center justify-center border border-green-900/30">
                 <Check size={14} />
             </div>
         ) : (
            <div className="flex items-center bg-[#161616] rounded-lg border border-[#222]">
                {quantity > 0 && (
                    <>
                        <button 
                            onClick={() => onUpdate(-1)}
                            className="w-8 h-8 flex items-center justify-center text-neutral-400 hover:text-white transition-colors"
                        >
                            <Minus size={14} />
                        </button>
                        <span className="text-xs font-medium w-5 text-center text-white">{quantity}</span>
                    </>
                )}
                <button 
                    onClick={() => onUpdate(1)}
                    className={`w-8 h-8 flex items-center justify-center transition-colors ${quantity > 0 ? 'text-white hover:bg-neutral-800 rounded-r-lg' : 'text-neutral-400 hover:text-white hover:bg-neutral-800 rounded-lg'}`}
                >
                    <Plus size={14} />
                </button>
            </div>
         )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, Type, FunctionDeclaration } from "@google/genai";
import { Message } from '../types';
import { Sparkles, Send, Bot, User, Loader2 } from 'lucide-react';

const tools: FunctionDeclaration[] = [
  {
    name: 'addToCart',
    description: 'Add a service or option to the user\'s cart.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        itemId: {
          type: Type.STRING,
          description: 'The ID of the item to add (e.g., short_mix, full_mix, pitch_correction, revision, add_person, add_track, add_minute, remove_signature, private_portfolio)',
        },
        quantity: {
          type: Type.NUMBER,
          description: 'Quantity to add (default 1). For base services, usually 1.',
        }
      },
      required: ['itemId']
    }
  },
  {
    name: 'setCommercial',
    description: 'Enable or disable commercial use multiplier.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        enabled: {
          type: Type.BOOLEAN,
          description: 'True to enable commercial mode (x3 price), false to disable.',
        }
      },
      required: ['enabled']
    }
  }
];

interface ChatProps {
  onToolCall: (toolName: string, args: any) => void;
}

export const Chat: React.FC<ChatProps> = ({ onToolCall }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      text: '안녕하세요! 작업하실 곡의 인원, MR포함 총 트랙 수, 보정 여부와 함께 상업적 이용 여부를 알려주시면 자동으로 견적을 도와드릴게요!'
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      if (!process.env.API_KEY) {
         throw new Error("API Key not found");
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const history = messages.map(m => ({
          role: m.role === 'model' ? 'model' : 'user',
          parts: [{ text: m.text }]
      }));

      const model = 'gemini-2.5-flash-latest';

      const systemInstruction = `
        You are the "Smart Auto-Quote" assistant for "THE MILLI MIX".
        Prices:
        - Short Mix: 10,000 KRW (short_mix)
        - Full Mix: 30,000 KRW (full_mix)
        - Options (10k each): pitch_correction, revision, add_person, add_track, add_minute
        - Remove Signature/Private: 50,000 KRW
        - Commercial: x3
        If user describes a project, use tools to add items. Confirm actions briefly in Korean.
      `;

      const result = await ai.models.generateContent({
        model,
        contents: [...history, { role: 'user', parts: [{ text: userMsg.text }] }],
        config: {
          systemInstruction,
          tools: [{ functionDeclarations: tools }],
        }
      });

      const response = result.response;
      let responseText = '';

      const functionCalls = response.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {
            onToolCall(call.name, call.args);
        }
        responseText = response.text || "견적에 반영해드렸습니다.";
      } else {
        responseText = response.text || "죄송합니다. 다시 말씀해 주시겠어요?";
      }

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "오류가 발생했습니다." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[400px] w-full bg-[#080808] rounded-2xl border border-neutral-900 overflow-hidden relative">

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-5 space-y-6 scrollbar-hide pt-6">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`
                        w-6 h-6 rounded-full flex items-center justify-center shrink-0 border
                        ${msg.role === 'model' ? 'bg-[#111] border-neutral-800 text-purple-400' : 'bg-neutral-800 border-neutral-700 text-neutral-300'}
                    `}>
                        {msg.role === 'model' ? <Bot size={12} /> : <User size={12} />}
                    </div>
                    <div className={`
                        max-w-[85%] rounded-lg px-3 py-2 text-xs leading-relaxed
                        ${msg.role === 'model' 
                            ? 'bg-[#161616] text-neutral-300 rounded-tl-none border border-neutral-800' 
                            : 'bg-neutral-800 text-neutral-200 rounded-tr-none border border-neutral-700'}
                    `}>
                        {msg.text}
                    </div>
                </div>
            ))}
            {isLoading && (
                 <div className="flex gap-3">
                    <div className="w-6 h-6 rounded-full bg-[#111] border border-neutral-800 text-purple-400 flex items-center justify-center shrink-0">
                        <Bot size={12} />
                    </div>
                    <div className="bg-[#161616] border border-neutral-800 rounded-lg rounded-tl-none px-3 py-2 flex items-center">
                        <Loader2 size={12} className="animate-spin text-neutral-500" />
                    </div>
                 </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="p-3 bg-[#0a0a0a] border-t border-neutral-900">
            <div className="relative">
                <input
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="작업 내용을 입력하세요..."
                    className="w-full bg-[#050505] border border-neutral-800 rounded-lg py-2.5 pl-3 pr-10 text-xs text-white placeholder-neutral-700 focus:outline-none focus:border-neutral-600 transition-colors"
                />
                <button 
                    onClick={handleSend}
                    disabled={isLoading}
                    className="absolute right-2 top-1/2 -translate-y-1/2 p-1 text-neutral-600 hover:text-white disabled:opacity-50 transition-colors"
                >
                    <Send size={12} />
                </button>
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Camera, ShoppingBag, X, ArrowRight, Sparkles } from 'lucide-react';
import { ServiceCard } from './components/ServiceCard';
import { OptionCard } from './components/OptionCard';
import { Chat } from './components/Chat';
import { BASE_SERVICES, OPTIONS, COMMERCIAL_OPTION } from './constants';
import { CartItem, ServiceItem } from './types';

export default function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCommercial, setIsCommercial] = useState(false);

  // Calculate total
  const subtotal = cart.reduce((sum, item) => sum + (item.item.price * item.quantity), 0);
  const total = isCommercial ? subtotal * 3 : subtotal;

  // Handlers
  const handleServiceSelect = (service: ServiceItem) => {
    setCart(prev => {
      // Remove other base services
      const filtered = prev.filter(item => item.item.type !== 'base');
      // Add new service
      return [...filtered, { id: service.id, quantity: 1, item: service }];
    });
  };

  const handleOptionUpdate = (optionId: string, delta: number) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === optionId);
      const option = OPTIONS.find(o => o.id === optionId);
      if (!option) return prev;

      if (existing) {
        const newQty = existing.quantity + delta;
        if (newQty <= 0) {
          return prev.filter(i => i.id !== optionId);
        }
        return prev.map(i => i.id === optionId ? { ...i, quantity: newQty } : i);
      } else if (delta > 0) {
        return [...prev, { id: optionId, quantity: delta, item: option }];
      }
      return prev;
    });
  };

  const handleCommercialToggle = () => {
    setIsCommercial(!isCommercial);
  };

  // Tool Call Handler (from AI)
  const handleToolCall = (name: string, args: any) => {
    if (name === 'addToCart') {
      const { itemId, quantity = 1 } = args;

      // Check if it's a base service
      const baseService = BASE_SERVICES.find(s => s.id === itemId);
      if (baseService) {
        handleServiceSelect(baseService);
        return;
      }

      // Check options
      const option = OPTIONS.find(o => o.id === itemId);
      if (option) {
         setCart(prev => {
             const existing = prev.find(i => i.id === itemId);
             if (existing) {
                 return prev.map(i => i.id === itemId ? { ...i, quantity: existing.quantity + quantity } : i);
             }
             return [...prev, { id: itemId, quantity, item: option }];
         });
      }
    } else if (name === 'setCommercial') {
      setIsCommercial(args.enabled);
    }
  };

  const handleSaveScreen = () => {
    window.print();
  };

  return (
    <div className="min-h-screen bg-[#050505] text-neutral-200 selection:bg-purple-500/30 font-inter pb-32">

      {/* Hero Header */}
      <header className="pt-32 pb-16 text-center">
        <div className="animate-fade-in-down">
            <h1 className="text-4xl md:text-5xl font-light tracking-[0.3em] text-white mb-4">THE MILLI MIX</h1>
            <p className="text-[10px] text-neutral-500 tracking-[0.4em] uppercase">믹싱 마스터링 커미션</p>
        </div>

        <nav className="flex items-center justify-center gap-12 mt-20 text-[11px] font-medium tracking-widest text-neutral-500 uppercase">
            <a href="#" className="hover:text-white transition-colors border-b border-white pb-1 text-white">Services</a>
            <a href="#" className="hover:text-white transition-colors border-b border-transparent pb-1">Portfolio</a>
            <button onClick={handleSaveScreen} className="flex items-center gap-2 hover:text-white transition-colors border-b border-transparent pb-1">
                <Camera size={14} />
                <span>Save Screen</span>
            </button>
        </nav>
      </header>

      <main className="max-w-[1600px] mx-auto px-6 md:px-12 grid grid-cols-1 lg:grid-cols-12 gap-x-12 lg:gap-x-20 gap-y-16">

        {/* Left Column: Services & Options */}
        <div className="lg:col-span-8 space-y-16">

            {/* Section 1: Main Services */}
            <section>
                <div className="mb-8">
                    <h2 className="text-xl font-normal text-white mb-2">서비스 선택</h2>
                    <p className="text-xs text-neutral-500 font-light">곡의 퀄리티를 완성할 핵심 엔지니어링 서비스입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-6">
                    {BASE_SERVICES.map(service => (
                        <ServiceCard 
                            key={service.id}
                            service={service}
                            isSelected={cart.some(item => item.id === service.id)}
                            onSelect={handleServiceSelect}
                        />
                    ))}
                </div>
            </section>

            {/* Section 2: Options */}
            <section>
                <div className="mb-8">
                    <h2 className="text-xl font-normal text-white mb-2">에디팅 & 옵션</h2>
                    <p className="text-xs text-neutral-500 font-light">필요에 따라 추가적인 디테일을 보강할 수 있는 옵션 항목입니다.</p>
                </div>
                <div className="grid md:grid-cols-2 gap-3">
                    {OPTIONS.map(option => (
                        <OptionCard
                            key={option.id}
                            option={option}
                            quantity={cart.find(i => i.id === option.id)?.quantity || 0}
                            onUpdate={(delta) => handleOptionUpdate(option.id, delta)}
                        />
                    ))}
                    {/* Commercial Option */}
                    <div className="md:col-span-2 mt-1">
                        <OptionCard 
                            option={COMMERCIAL_OPTION}
                            quantity={0}
                            onUpdate={handleCommercialToggle}
                            isMultiplier={true}
                            isActive={isCommercial}
                        />
                    </div>
                </div>
            </section>

            {/* Custom Project Banner */}
            <section>
                 <div className="relative overflow-hidden rounded-2xl border border-dashed border-neutral-800 bg-[#080808] p-8 flex items-center justify-between">
                    <div>
                        <h3 className="text-xl font-bold text-white mb-2">Custom Project</h3>
                        <p className="text-sm text-neutral-500">앨범 단위(EP/LP) 또는 정기 작업 문의는 별도의 커스텀 견적이 적용됩니다.</p>
                    </div>
                    <button className="flex items-center gap-2 text-xs font-medium text-neutral-300 hover:text-white border border-neutral-800 hover:border-neutral-600 rounded px-5 py-3 transition-all z-10 bg-neutral-900/50">
                        상담하기
                        <ArrowRight size={14} />
                    </button>
                 </div>
            </section>
        </div>

        {/* Right Column: Sidebar (Sticky) */}
        <div className="lg:col-span-4 space-y-6 lg:sticky lg:top-8 lg:self-start">

            {/* Cart Summary */}
            <div className="bg-[#080808] border border-neutral-900 rounded-2xl min-h-[300px] flex flex-col relative overflow-hidden">
                {cart.length === 0 ? (
                    <div className="flex-1 flex flex-col items-center justify-center text-neutral-600 gap-5 py-20">
                        <div className="w-16 h-16 rounded-full border-2 border-neutral-800/50 flex items-center justify-center text-neutral-700">
                            <ShoppingBag size={20} />
                        </div>
                        <span className="text-[10px] font-semibold tracking-[0.2em] text-neutral-600">YOUR CART IS EMPTY</span>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col p-6">
                        <div className="flex items-center justify-between mb-8 pb-4 border-b border-neutral-900">
                             <div className="flex items-center gap-2 text-neutral-400">
                                <ShoppingBag size={14} />
                                <span className="text-xs font-medium tracking-widest uppercase">Estimate</span>
                             </div>
                             <button 
                                onClick={() => { setCart([]); setIsCommercial(false); }}
                                className="text-[10px] text-neutral-600 hover:text-red-400 transition-colors uppercase tracking-wider"
                            >
                                Clear All
                            </button>
                        </div>

                        <div className="flex-1 space-y-4 mb-8">
                            {cart.map(cartItem => (
                                <div key={cartItem.id} className="flex justify-between items-start text-sm group">
                                    <div className="pr-4">
                                        <div className="text-neutral-300 font-medium mb-1">{cartItem.item.name}</div>
                                        {cartItem.quantity > 1 && (
                                            <div className="inline-flex items-center text-[10px] bg-neutral-900 text-neutral-500 px-1.5 py-0.5 rounded">Qty: {cartItem.quantity}</div>
                                        )}
                                    </div>
                                    <div className="text-white font-medium whitespace-nowrap">
                                        ₩{(cartItem.item.price * cartItem.quantity).toLocaleString()}
                                    </div>
                                </div>
                            ))}
                            {isCommercial && (
                                <div className="flex justify-between items-center text-sm pt-4 border-t border-neutral-900 text-indigo-400">
                                    <div className="font-medium flex items-center gap-2">
                                        Commercial Use
                                        <span className="text-[10px] bg-indigo-950 text-indigo-300 px-1.5 py-0.5 rounded border border-indigo-900/50">x3.0</span>
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="pt-6 border-t border-neutral-900 mt-auto">
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-neutral-500 text-xs uppercase tracking-wider">Total</span>
                                <span className="text-2xl font-bold text-white tracking-tight">₩{total.toLocaleString()}</span>
                            </div>
                            <p className="text-[10px] text-neutral-700 text-right">VAT included</p>
                        </div>
                    </div>
                )}
            </div>

            {/* Smart Chat */}
            <Chat onToolCall={handleToolCall} />

            <div className="text-center">
                 <p className="text-[9px] text-neutral-700 tracking-[0.2em] mt-8 uppercase">Auto Quote Engine Powered by The Milli Mix</p>
            </div>

        </div>

      </main>

      {/* Footer */}
      <footer className="text-center py-24 text-[10px] text-neutral-600 tracking-[0.3em] font-light">
        THE MILLI MIX <br/><br/> © 2026 THE MILLI MIX. PROFESSIONAL AUDIO ENGINEERING.
      </footer>
    </div>
  );
}

