      const functionCalls = response.functionCalls;
      if (functionCalls && functionCalls.length > 0) {
        for (const call of functionCalls) {
            onToolCall(call.name, call.args);
        }
        responseText = response.text || "견적에 반영해드렸습니다.";
      } else {
        responseText = response.text || "죄송합니다. 다시 말씀해 주시겠어요?";
      }

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: responseText }]);

    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "오류가 발생했습니다." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col w-full relative">

        {/* Messages - only visible if content exists */}
        {(messages.length > 0 || isLoading) && (
            <div className="mb-4 space-y-4 max-h-[400px] overflow-y-auto scrollbar-hide p-2">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                        <div className={`
                            w-6 h-6 rounded-full flex items-center justify-center shrink-0 border
                            ${msg.role === 'model' ? 'bg-[#111] border-neutral-800 text-purple-400' : 'bg-neutral-800 border-neutral-700 text-neutral-300'}
                        `}>
                            {msg.role === 'model' ? <Bot size={12} /> : <User size={12} />}
                        </div>
                        <div className={`
                            max-w-[90%] text-xs leading-relaxed pt-1
                            ${msg.role === 'model' 
                                ? 'text-neutral-300' 
                                : 'text-neutral-200 text-right'}
                        `}>
                            {msg.text}
                        </div>
                    </div>
                ))}
                {isLoading && (
                     <div className="flex gap-3">
                        <div className="w-6 h-6 rounded-full bg-[#111] border border-neutral-800 text-purple-400 flex items-center justify-center shrink-0">
                            <Bot size={12} />
                        </div>
                        <div className="pt-1">
                            <Loader2 size={12} className="animate-spin text-neutral-500" />
                        </div>
                     </div>
                )}
                <div ref={messagesEndRef} />
            </div>
        )}

        {/* Input */}
        <div className="relative">
            <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder="작업 내용을 입력하세요..."
                className="w-full bg-[#080808] border border-neutral-900 rounded-xl py-3 pl-4 pr-10 text-xs text-white placeholder-neutral-600 focus:outline-none focus:border-neutral-700 transition-colors"
            />
            <button 
                onClick={handleSend}
                disabled={isLoading}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-neutral-600 hover:text-white disabled:opacity-50 transition-colors"
            >
                <Send size={14} />
            </button>
        </div>
    </div>
  );
};

