    setCart(prev => {
      const existing = prev.find(i => i.id === itemId);

      // If item exists in cart, update quantity
      if (existing) {
        const newQty = existing.quantity + delta;
        if (newQty <= 0) {
          return prev.filter(i => i.id !== itemId);
        }
        return prev.map(i => i.id === itemId ? { ...i, quantity: newQty } : i);
