      // If item is not in cart and we are adding (delta > 0), find and add it
      if (delta > 0) {
        const itemDef = [...BASE_SERVICES, ...OPTIONS].find(i => i.id === itemId);
        if (itemDef) {
           return [...prev, { id: itemId, quantity: delta, item: itemDef }];
