            <h1 className="text-6xl md:text-8xl font-light tracking-[0.3em] text-white mb-6">THE MILLI MIX</h1>
            <p className="text-sm md:text-base text-neutral-500 tracking-[0.6em] uppercase">믹싱 마스터링 커미션</p>
