        content += `\n[옵션]\n`;
        content += `• ${COMMERCIAL_OPTION.name} (${COMMERCIAL_OPTION.unit})\n`;
        content += `  +₩${commercialCost.toLocaleString()}\n`;
    }

    content += `\n------------------------------------------------\n`;
    content += `총 트랙 수 : ${totalTracks} Tracks\n`;
    content += `총 합계    : ₩${total.toLocaleString()} (VAT 포함)\n`;
    content += `------------------------------------------------\n`;
    content += `\n* 본 견적서는 단순 참고용입니다.\n`;

    const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `THE_MILLI_MIX_Estimate_${Date.now()}.txt`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

