                    </section>
                </div>

                {/* Right Column: Sidebar */}
                <div className="lg:col-span-4">

                    {/* Spacer to align Cart with Service Cards */}
                    <div className="hidden lg:block h-[84px]" aria-hidden="true"></div>

                    {/* Cart Summary */}
                    <div className="sticky top-8 bg-[#080808] border border-neutral-900 rounded-2xl min-h-[300px] flex flex-col relative overflow-hidden">
                        {cart.length === 0 ? (
