        className="fixed left-[-9999px] top-0 w-[210mm] min-h-[297mm] bg-white text-black p-12 font-sans"
        style={{ zIndex: -50 }}
      >
        {/* Header */}
        <div className="text-center mb-12 border-b-2 border-black pb-8">
